import{c as t,a7 as l,y as r,B as e}from"./chunks/framework.3cjvm90C.js";const g=JSON.parse('{"title":"具身智能","description":"介绍具身智能的基本概念、研究方向与代表性工作","frontmatter":{"title":"具身智能","description":"介绍具身智能的基本概念、研究方向与代表性工作"},"headers":[],"relativePath":"rlwiki/robots/embodyai.md","filePath":"rlwiki/robots/embodyai.md","lastUpdated":1782448598000}'),i={name:"rlwiki/robots/embodyai.md"};function o(n,a,s,h,b,d){return l(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="具身智能" tabindex="-1">具身智能 <a class="header-anchor" href="#具身智能" aria-label="Permalink to “具身智能”">​</a></h1><h2 id="具身智能的定义与核心要素" tabindex="-1">具身智能的定义与核心要素 <a class="header-anchor" href="#具身智能的定义与核心要素" aria-label="Permalink to “具身智能的定义与核心要素”">​</a></h2><p>具身智能作为人工智能发展的一个重要分支，正在迅速崭露头角，成为科技界和大众关注的热门话题。具身智能是通过在物理世界和数字世界的学习和进化，达到理解世界、互动交互并完成任务的目标。具身智能是一个由“本体”和“智能体”两部分耦合而成的智能系统，能够在复杂环境中执行任务。</p><p>具身智能需要具有如下的几个核心要素：</p><ol><li><strong>本体</strong>：作为实际的执行者，是在物理或者虚拟世界进行感知和任务执行的机构。本体通常是具有物理实体的机器人，可以有多种形态。</li><li><strong>智能体（Embodied Agents）</strong>：是具身在本体之上的智能核心，负责感知、理解、决策、控制等核心工作。</li><li><strong>数据</strong>：数据是泛化的关键，但是涉及机器人的数据不仅稀缺，而且昂贵。</li><li><strong>学习和进化架构</strong>：智能体通过和虚拟或者真实的物理世界的交互来适应新的环境、学习新的知识，并强化出新的解决问题方法。</li></ol><h2 id="具身智能的科研与技术进展" tabindex="-1">具身智能的科研与技术进展 <a class="header-anchor" href="#具身智能的科研与技术进展" aria-label="Permalink to “具身智能的科研与技术进展”">​</a></h2><p>在基于 Transformer 的大语言模型浪潮带领下，微软、谷歌、英伟达等大厂以及斯坦福、卡耐基梅隆等高等学府都开展了具身智能的相关研究。具有代表性的项目包括：</p><ul><li>微软基于 ChatGPT 的强大自然语言理解和推理能力，能够生成控制机器人的相关代码。</li><li>英伟达的 VIMA 基于 T5 模型，将文本和多模态输入交错融合，可以结合历史信息预测机器人的下一步行动动作。</li><li>斯坦福大学利用大语言模型的理解、推理和代码能力与 VLM 交互并生成 3D value map 来规划机械臂的运行轨迹。</li><li>谷歌的具身智能路线就比较多了，包括从 PaLM 衍生来的 PaLM-E，从 Gato 迭代来的 RoboCat，以及最新基于 RT-1 和 PaLM-E 升级得到的 RT-2。</li></ul><h2 id="具身智能的挑战" tabindex="-1">具身智能的挑战 <a class="header-anchor" href="#具身智能的挑战" aria-label="Permalink to “具身智能的挑战”">​</a></h2><p>虽然具身智能作为迈向通用人工智能（AGI）的重要一步，是学术界和产业界的热点，但要实现好的具身智能，仍然面临着算法、工程技术、数据、场景和复杂软硬件等诸多挑战。</p><ol><li><strong>强大的通用本体平台</strong>：需要解决硬件的关键零部件技术突破，形成具有优秀运动能力和操作能力的平台级通用机器人产品。</li><li><strong>设计强大的智能体系统</strong>：需要解决物理 3D 环境精确感知、任务编排与执行、强大的通识能力、多级语义推理能力、人机口语多轮交互能力、long-term 记忆能力、个性化情感关怀能力、强大的任务泛化与自学迁移能力等。</li><li><strong>高质量的行业数据</strong>：现实场景的复杂多变，使得现阶段缺乏足够的场景数据来训练一个完全通用的大模型。</li><li><strong>持续学习和进化的能力</strong>：需要通过虚拟和真实的交互，实现智能体的持续学习和进化。</li></ol><h3 id="具身智能开源平台" tabindex="-1">具身智能开源平台 <a class="header-anchor" href="#具身智能开源平台" aria-label="Permalink to “具身智能开源平台”">​</a></h3><h2 id="habitat-lab" tabindex="-1">habitat-lab <a class="header-anchor" href="#habitat-lab" aria-label="Permalink to “habitat-lab”">​</a></h2><ul><li><a href="https://github.com/facebookresearch/habitat-lab" target="_blank" rel="noreferrer">https://github.com/facebookresearch/habitat-lab</a></li></ul><p>Habitat-Lab 是一个模块化高水平的代码库，用于端到端开发具身人工智能。它旨在训练智能体在室内环境中执行各种具身人工智能任务，以及开发在执行这些任务时可以与人类互动的智能体。</p><p>为了实现这一目标， Habitat-Lab 旨在支持以下功能：</p><ul><li><strong>灵活的任务定义</strong>：允许用户训练智能体执行各种单智能体和多智能体任务（例如导航、重新排列、指令跟踪、问答、人类跟踪），以及定义新任务。</li><li><strong>多样化的具体智能体</strong>：配置和实例化多样化的具体智能体，包括商业机器人和人形机器人，并指定它们的传感器和功能。</li><li><strong>训练和评估代理</strong>：提供单智能体和多智能体训练的算法（通过模仿或强化学习），以及使用标准指标对定义的任务上的性能进行基准测试的工具。</li></ul><h2 id="allenact" tabindex="-1">AllenAct <a class="header-anchor" href="#allenact" aria-label="Permalink to “AllenAct”">​</a></h2><p><strong>AllenAct</strong>是一个模块化且灵活的学习框架，其设计重点是满足 Embodied-AI 研究的独特需求。它为日益增多的具身环境、任务和算法提供一流的支持，提供最先进模型的复现，并包含大量文档、教程、启动代码和预训练模型。</p>',19)])])}const p=t(i,[["render",o]]);export{g as __pageData,p as default};
